var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이걸 이렇게 해서...... 여기에 꽂으면......","JPN":"これをこうして……ここに刺したら……","ENG":"So if I take this... and plug it here...","TWN":"把這個這樣……只要插在這裡的話……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"앗 뜨거! 젠장!","JPN":"熱っ！　ったく！","ENG":"Ah, that’s hot! Damn it!","TWN":"啊好燙！該死！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래도 이제 거의 다 된 것 같은데......","JPN":"でも、これでほぼ終わったはずだ……","ENG":"Still, I think I’m almost done here...","TWN":"不過所有的事情都做了……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"메이슨이다. 이쪽은 대충 끝나간다.","JPN":"メイソンだ。こっちはもうすぐ完了する。","ENG":"This is Mason. I’m almost finished.","TWN":"我是梅森，這邊差不多結束了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그쪽은 좀 어때? 살아있나?","JPN":"そっちはどうだ？　生きてるか？","ENG":"How's everything over there? Is everyone alive?","TWN":"那邊怎麼樣？人還活著嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"오, 메이슨 씨. 건강한 목소리를 들으니 반갑네요.","JPN":"おお、メイソンさん。元気な声を聞けてなによりです。","ENG":"Hello, Mr. Mason. I’m happy to hear you're alive and well.","TWN":"喔，梅森先生。很高興聽到你的聲音這麼有精神。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이런 젠장......","JPN":"クソ……","ENG":"Damn it...","TWN":"天殺的……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"왜 네가 이 무전기로 대답하는 거지?","JPN":"なぜあんたがその無線機でしゃべってるんだ？","ENG":"Why are you answering this radio call?","TWN":"為什麼是你用這個對講機在回答？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다른 사람들은 설마.......","JPN":"他の人たちはまさか……","ENG":"Did the others....","TWN":"其他人難道……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"하하하. 너무 걱정 마세요.","JPN":"ははは。そんなに心配しなくてもいいですよ。","ENG":"Hahaha... Don't worry.","TWN":"哈哈哈，不要太擔心。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"다들 바퀴벌레 같아서 도망치는 거 하나는 기가 막히잖아요?","JPN":"みんな、ゴキブリみたいに逃げ足の速さだけは抜群でしょう？","ENG":"Your friends sure know how to run and hide like cockroaches.","TWN":"大家都像蟑螂一樣逃跑了，真是太厲害了。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이래서 제가 용병들을 싫어한다니까요.","JPN":"これだから私は傭兵たちが嫌いなんです。","ENG":"This is why I despise mercenaries.","TWN":"所以我才討厭傭兵。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"약해 빠진 것들이 잔머리만 늘어서 정말...... 귀찮고 짜증난달까?","JPN":"弱いくせに悪知恵ばかり働かせるから、\\nまったく……面倒でイラつくというか。","ENG":"Just a bunch of sneaky weaklings... Pesky, annoying little things.","TWN":"弱小又只會耍小聰明……真是煩到不行。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......부정할 수가 없군.","JPN":"……それは否定できないな。","ENG":"I guess I can’t deny that.","TWN":"……我無法否認呢。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"용병 놈들이 생명력 하나는 질긴 편이지.","JPN":"傭兵の生命力の強さは認めるしかない。","ENG":"Mercenaries are nothing if not resilient.","TWN":"傭兵們的生命力通常都是非常強的。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그런데 왜 그런 걸 나한테 말하는데?","JPN":"ところで、どうしてそんなことを俺に言うんだ？","ENG":"Why are you talking to me about this anyway?","TWN":"但你為什麼要跟我說這些？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"당연히 시간 끌기죠. 무선 발신지를 역추적 중이거든요.","JPN":"もちろん時間稼ぎですよ。無線の発信地を逆探知してるんです。","ENG":"To buy time, of course. We're tracking the source of your transmission.","TWN":"當然是在拖時間了，因為我正在逆向追蹤你的無線電發信地點。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};